import json,glob
tot=0; sess=0
for f in sorted(glob.glob('transcripts/*.jsonl')):
    n=0
    for line in open(f):
        try: r=json.loads(line)
        except: continue
        if r.get('type')=='system' and 'compactMetadata' in r: n+=1
    if n: sess+=1; tot+=n
print('sessions with compactMetadata:', sess, 'of', len(glob.glob(\"transcripts/*.jsonl\")), '| total markers:', tot)
# field names present
import collections
keys=collections.Counter()
for f in glob.glob('transcripts/*.jsonl'):
    for line in open(f):
        try: r=json.loads(line)
        except: continue
        if r.get('type')=='system' and 'compactMetadata' in r:
            keys.update(r['compactMetadata'].keys())
print('compactMetadata fields:', dict(keys))
